@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

html, body, .card {
    width: 100%;
    height: 100%;
}

.card {
    display: flex;
    align-items: center;
    background: linear-gradient(135deg, rgba(45, 45, 58, 0.95) 0%, rgba(30, 30, 42, 0.95) 100%) !important;
    backdrop-filter: blur(10px);
    border-radius: 16px;
    border: 1px solid rgba(74, 74, 90, 0.6);
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4), inset 0 1px 0 rgba(255, 255, 255, 0.05);
    color: #E5E7EB;
    position: relative;
    overflow: hidden;
    animation: fadeIn 0.6s ease-out;
    transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.card::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(59, 130, 246, 0.1), transparent);
    animation: shimmer 3s infinite;
}

@keyframes shimmer {
  0% { left: -100%; }
  100% { left: 100%; }
}

.card:hover {
    transform: translateY(-4px);
    border-color: rgba(59, 130, 246, 0.6);
    box-shadow: 0 12px 48px rgba(59, 130, 246, 0.25), inset 0 1px 0 rgba(255, 255, 255, 0.1);
}

.image-container {
    flex: 0 0 auto;
    margin: 0 24px;
    position: relative;
    z-index: 2;
    padding: 16px;
    background: linear-gradient(135deg, rgba(26, 26, 42, 0.9) 0%, rgba(20, 20, 32, 0.9) 100%);
    backdrop-filter: blur(8px);
    border-radius: 12px;
    border: 1px solid rgba(74, 74, 90, 0.5);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3), inset 0 1px 0 rgba(255, 255, 255, 0.05);
    transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

.image-container:hover {
    border-color: rgba(59, 130, 246, 0.6);
    background: linear-gradient(135deg, rgba(59, 130, 246, 0.15) 0%, rgba(139, 92, 246, 0.1) 100%);
    transform: scale(1.05);
    box-shadow: 0 6px 24px rgba(59, 130, 246, 0.3), inset 0 1px 0 rgba(255, 255, 255, 0.1);
}

.image-container img {
    margin-left: 0;
    border-radius: 8px;
    height: 75px;
    width: auto;
    transition: all 0.3s ease;
}

.data-container-nome {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    overflow: hidden;
    padding-right: 20px;
    text-align: center;
    position: relative;
    z-index: 2;
}

.adapted-value {
    font-size: clamp(36px, 2vw, 42px);
    font-weight: 800;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    width: 100%;
    background: linear-gradient(135deg, #E5E7EB 0%, #3B82F6 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    transition: all 0.4s ease;
    letter-spacing: 0.8px;
    font-family: 'Inter', 'Poppins', -apple-system, BlinkMacSystemFont, sans-serif;
}

.card:hover .adapted-value {
    background: linear-gradient(135deg, #3B82F6 0%, #8B5CF6 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    transform: scale(1.02);
}

.adapted-name {
    font-size: clamp(12px, 1.25vw, 22px);
    color: #9CA3AF;
    margin-top: 10px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    width: 100%;
    opacity: 0.9;
}

@keyframes fadeInUp {
    from {
      opacity: 0;
      transform: translateY(20px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }

  @keyframes pulse {
    0%, 100% {
      opacity: 1;
      transform: scale(1);
    }
    50% {
      opacity: 0.8;
      transform: scale(1.05);
    }
  }

  @keyframes shimmer {
    0% {
      background-position: -200% 0;
    }
    100% {
      background-position: 200% 0;
    }
  }

  @keyframes slideIn {
    from {
      width: 0;
    }
    to {
      width: 85%;
    }
  }

  * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  .plano-wrapper {
    width: 100%;
    height: 100%;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 16px;
  }

  .plano-card {
    width: 100%;
    height: 100%;
    background: linear-gradient(135deg, rgba(26, 26, 42, 0.98) 0%, rgba(30, 30, 45, 0.98) 100%);
    backdrop-filter: blur(20px);
    border-radius: 18px;
    border: 1px solid rgba(74, 74, 90, 0.4);
    box-shadow: 
      0 8px 32px rgba(0, 0, 0, 0.5),
      inset 0 1px 0 rgba(255, 255, 255, 0.08),
      0 0 0 1px rgba(59, 130, 246, 0.1);
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    padding: 24px;
    transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);
    animation: fadeInUp 0.6s ease-out;
  }

  .plano-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 2px;
    background: linear-gradient(90deg, transparent, #3B82F6, #8B5CF6, transparent);
    background-size: 200% 100%;
    animation: shimmer 3s infinite;
    opacity: 0.6;
  }

  .plano-card::after {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle, rgba(59, 130, 246, 0.1) 0%, transparent 70%);
    opacity: 0;
    transition: opacity 0.5s ease;
  }

  .plano-card:hover {
    transform: translateY(-4px);
    border-color: rgba(59, 130, 246, 0.5);
    box-shadow: 
      0 16px 48px rgba(59, 130, 246, 0.3),
      inset 0 1px 0 rgba(255, 255, 255, 0.12),
      0 0 0 1px rgba(59, 130, 246, 0.2);
  }

  .plano-card:hover::after {
    opacity: 1;
  }

  .plano-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 20px;
    position: relative;
    z-index: 2;
  }

  .plano-icon-wrapper {
    position: relative;
    width: 64px;
    height: 64px;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .plano-icon {
    width: 48px;
    height: 48px;
    color: #3B82F6;
    filter: drop-shadow(0 4px 12px rgba(59, 130, 246, 0.4));
    transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
    z-index: 2;
    position: relative;
  }

  .icon-glow {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 64px;
    height: 64px;
    background: radial-gradient(circle, rgba(59, 130, 246, 0.3) 0%, transparent 70%);
    border-radius: 50%;
    animation: pulse 2s ease-in-out infinite;
    z-index: 1;
  }

  .plano-card:hover .plano-icon {
    color: #8B5CF6;
    transform: scale(1.1) rotate(5deg);
    filter: drop-shadow(0 6px 20px rgba(139, 92, 246, 0.5));
  }

  .plano-badge {
    display: flex;
    align-items: center;
    gap: 8px;
    background: linear-gradient(135deg, rgba(34, 197, 94, 0.15) 0%, rgba(34, 197, 94, 0.08) 0%);
    border: 1px solid rgba(34, 197, 94, 0.3);
    border-radius: 12px;
    padding: 6px 12px;
    backdrop-filter: blur(8px);
    box-shadow: 0 2px 8px rgba(34, 197, 94, 0.2), inset 0 1px 0 rgba(255, 255, 255, 0.1);
  }

  .badge-dot {
    width: 8px;
    height: 8px;
    background: #22C55E;
    border-radius: 50%;
    box-shadow: 0 0 12px rgba(34, 197, 94, 0.8);
    animation: pulse 2s ease-in-out infinite;
  }

  .badge-text {
    font-family: 'Inter', 'Poppins', -apple-system, BlinkMacSystemFont, sans-serif;
    font-size: 10px;
    font-weight: 700;
    letter-spacing: 1.2px;
    color: #22C55E;
    text-transform: uppercase;
  }

  .plano-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    justify-content: center;
    position: relative;
    z-index: 2;
  }

  .plano-label {
    font-family: 'Inter', 'Poppins', -apple-system, BlinkMacSystemFont, sans-serif;
    font-size: 10px;
    font-weight: 600;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: #9CA3AF;
    margin-bottom: 12px;
    opacity: 0.9;
  }

  .plano-value {
    font-family: 'Inter', 'Poppins', -apple-system, BlinkMacSystemFont, sans-serif;
    font-size: clamp(28px, 4vw, 36px);
    font-weight: 900;
    line-height: 1.1;
    background: linear-gradient(135deg, #E5E7EB 0%, #3B82F6 50%, #8B5CF6 100%);
    background-size: 200% 200%;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin-bottom: 8px;
    letter-spacing: -0.5px;
    transition: all 0.5s ease;
    animation: shimmer 3s ease-in-out infinite;
  }

  .plano-card:hover .plano-value {
    background-position: 100% 0;
    transform: scale(1.02);
  }

  .plano-subtitle {
    font-family: 'Inter', 'Poppins', -apple-system, BlinkMacSystemFont, sans-serif;
    font-size: 11px;
    font-weight: 500;
    color: #9CA3AF;
    letter-spacing: 0.5px;
    opacity: 0.8;
  }

  .plano-footer {
    margin-top: 16px;
    position: relative;
    z-index: 2;
  }

  .speed-indicator {
    width: 100%;
  }

  .speed-bar {
    width: 100%;
    height: 4px;
    background: rgba(74, 74, 90, 0.4);
    border-radius: 4px;
    overflow: hidden;
    position: relative;
    box-shadow: inset 0 2px 4px rgba(0, 0, 0, 0.3);
  }

  .speed-fill {
    height: 100%;
    width: 85%;
    background: linear-gradient(90deg, #3B82F6 0%, #8B5CF6 100%);
    border-radius: 4px;
    box-shadow: 0 0 12px rgba(59, 130, 246, 0.6);
    animation: slideIn 1.5s ease-out;
    position: relative;
    overflow: hidden;
  }

  .speed-fill::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.3), transparent);
    animation: shimmer 2s infinite;
  }

  @media (max-width: 768px) {
    .plano-card {
      padding: 20px;
      border-radius: 16px;
    }

    .plano-icon-wrapper {
      width: 56px;
      height: 56px;
    }

    .plano-icon {
      width: 40px;
      height: 40px;
    }

    .plano-value {
      font-size: 24px;
    }

    .plano-label {
      font-size: 9px;
    }

    .plano-subtitle {
      font-size: 10px;
    }
  }

